protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed â€” Cosmos DB provider now throws; manage indexing via Azure portal/Bicep.

    modelBuilder.Entity<Product>(b =>
    {
        b.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
        b.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the JSON id property.
        // Existing documents have id = "Product|123"; without this flag EF generates "123"
        // and all point-reads / FindAsync calls against existing data will fail.
        b.HasRootDiscriminatorInJsonId(true);
    });
}

