using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports sync I/O â€” use async throughout.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL â€” still works because we preserved "Discriminator" as the
        // discriminator property name via HasDiscriminator<string>("Discriminator").
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync ToList() throws in EF Core 9 Cosmos provider; use ToListAsync().
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

